   126→  filterSpecs: FilterSpec[];
   127→  onFilterChange?: (filter: SelectedFilter) => void;
   128→  onTimeSpanChange?: (timeSpan: TimeSpan) => void;
   129→  onLoadSourceData?: (query: SQLQuery) => Promise<string[]>;
   130→  timezone?: string;
