   136→
   137→function DashboardFilterWithReset({
   138→  filterRef,
   139→  filterSpecs,
   140→  onFilterChange,
   141→  onTimeSpanChange,
   142→  onLoadSourceData,
   143→  timezone,
   144→  showTimeSpanSelector,
   145→  showRefresh,
   146→  showAutoRefresh,
   147→  headerActions,
   148→}: DashboardFilterWithResetProps) {
   149→  const { resetLayout } = useDashboardLayout();
   150→
   151→  return (
   152→    <DashboardFilterComponent
   153→      ref={filterRef}
   154→      filterSpecs={filterSpecs}
   155→      onFilterChange={onFilterChange}
   156→      onTimeSpanChange={onTimeSpanChange}
   157→      onLoadSourceData={onLoadSourceData}
   158→      timezone={timezone}
   159→      showTimeSpanSelector={showTimeSpanSelector}
   160→      showRefresh={showRefresh}
   161→      showAutoRefresh={showAutoRefresh}
   162→      onResetLayout={resetLayout}
