   226→              dragConfig={{ enabled: true, bounded: false, handle: ".dashboard-drag-handle", threshold: 3 }}
   227→              compactor={verticalCompactor}
   228→            >
   229→              {panels.map((panel, localIndex) => {
   230→                const globalIndex = globalPanelStartIndex + localIndex;
   231→                const isPanelCollapsed = panelCollapseStates.get(globalIndex) ?? panel.collapsed ?? false;
   232→
   233→                return (
   234→                  <div key={`panel-${localIndex}`} className="h-full">
   235→                    <div className={cn("w-full h-full", isPanelCollapsed && "h-auto")}>
   236→                      <DashboardVisualizationPanel
   237→                        descriptor={panel}
   238→                        initialTimeSpan={initialTimeSpan}
   239→                        initialFilterExpression={initialFilterExpression}
   240→                        initialLoading={initialLoading}
   241→                        ref={(el) => onSubComponentUpdated(el, globalIndex)}
   242→                        onCollapsedChange={(collapsed) => onPanelCollapsedChange(globalIndex, collapsed)}
   243→                        onChartSelection={onChartSelection}
   244→                      />
   245→                    </div>
   246→                  </div>
   247→                );
   248→              })}
   249→            </ResponsiveGridLayout>
   250→          )}
   251→        </div>
   252→      )}
   253→
   254→      {!isCollapsed && panels.length === 0 && showEditControls && (
   255→        <div className="px-4 py-8 text-center text-sm text-muted-foreground border-b">
   256→          No panels in this section. Add panels to get started.
   257→        </div>
   258→      )}
   259→    </div>
