   140→  group: DashboardGroup | null; // null for ungrouped panels
   141→  sectionIndex: number;
   142→  panels: PanelDescriptor[];
   143→  globalPanelStartIndex: number; // Global index of first panel in this section
   144→}
   145→
   146→const DashboardPanelContainer = forwardRef<
   147→  DashboardPanelContainerRef,
   148→  DashboardPanelContainerProps
   149→>(
   150→  (
   151→    {
   152→      dashboard,
   153→      dashboardId,
   154→      initialTimeSpan,
   155→      initialFilterExpression,
   156→      initialLoading,
   157→      onChartSelection,
   158→      showSectionEditControls = false,
   159→      onSectionRename,
   160→      onSectionDelete,
   161→      onSectionCollapseChange,
   162→      children,
   163→    },
   164→    ref
   165→  ) => {
   166→    // Track individual panel collapse states (keyed by global panel index)
   167→    const [panelCollapseStates, setPanelCollapseStates] = useState<Map<number, boolean>>(new Map());
   168→    // Track section collapse states (keyed by section index) - local state, not persisted
   169→    const [sectionCollapseStates, setSectionCollapseStates] = useState<Map<number, boolean>>(new Map());
   170→    const subComponentRefs = useRef<(DashboardVisualizationComponent | null)[]>([]);
   171→
   172→    // Track registered refreshable children
   173→    const registeredChildrenRef = useRef<Set<RefreshableChild>>(new Set());
   174→
   175→    // Memoize the charts array from the dashboard
   176→    const panels = useMemo(() => dashboard.charts, [dashboard]);
   177→
   178→    // Build sections from dashboard panels
   179→    const sections = useMemo<SectionInfo[]>(() => {
   180→      const result: SectionInfo[] = [];
   181→      const ungroupedPanels: PanelDescriptor[] = [];
   182→      let globalPanelIndex = 0;
   183→      let sectionIndex = 0;
   184→
   185→      panels.forEach((item) => {
   186→        if (isDashboardGroup(item)) {
   187→          // This is a group - create a section for it
   188→          result.push({
   189→            group: item,
   190→            sectionIndex,
   191→            panels: item.charts,
   192→            globalPanelStartIndex: globalPanelIndex,
   193→          });
   194→          globalPanelIndex += item.charts.length;
   195→          sectionIndex++;
   196→        } else {
   197→          // Standalone panel - collect into ungrouped
   198→          ungroupedPanels.push(item);
   199→        }
   200→      });
   201→
   202→      // If there are ungrouped panels, add them as the last section (without header)
   203→      if (ungroupedPanels.length > 0) {
   204→        // Find the correct global start index for ungrouped panels
   205→        // They may be interleaved with groups, so we need to recalculate
   206→        let ungroupedStartIndex = 0;
   207→        panels.forEach((item) => {
   208→          if (isDashboardGroup(item)) {
   209→            ungroupedStartIndex += item.charts.length;
   210→          }
   211→        });
   212→
   213→        result.push({
   214→          group: null, // null indicates ungrouped section
   215→          sectionIndex,
   216→          panels: ungroupedPanels,
   217→          globalPanelStartIndex: ungroupedStartIndex,
   218→        });
   219→      }
   220→
   221→      return result;
   222→    }, [panels]);
   223→
   224→    // Initialize panel collapse states from descriptors
   225→    useEffect(() => {
   226→      setPanelCollapseStates((prev) => {
   227→        const next = new Map(prev);
   228→        let changed = false;
   229→        sections.forEach((section) => {
   230→          section.panels.forEach((panel, localIndex) => {
   231→            const globalIndex = section.globalPanelStartIndex + localIndex;
   232→            if (!prev.has(globalIndex)) {
   233→              next.set(globalIndex, panel.collapsed ?? false);
   234→              changed = true;
   235→            }
   236→          });
   237→        });
   238→        return changed ? next : prev;
   239→      });
   240→    }, [sections]);
   241→
   242→    // Store callback in ref to avoid stale closure in setState
   243→    const onSectionCollapseChangeRef = useRef(onSectionCollapseChange);
   244→    onSectionCollapseChangeRef.current = onSectionCollapseChange;
   245→
   246→    // Store sections in ref to access current value in toggle handler
   247→    const sectionsRef = useRef(sections);
   248→    sectionsRef.current = sections;
   249→
   250→    // Track pending collapse change to notify parent after state update
   251→    const pendingCollapseChangeRef = useRef<{ sectionIndex: number; collapsed: boolean } | null>(null);
   252→
   253→    // Toggle section collapse - uses local state, optionally notifies parent
   254→    const handleSectionToggle = useCallback((sectionIndex: number) => {
   255→      const section = sectionsRef.current.find(s => s.sectionIndex === sectionIndex);
   256→      const configCollapsed = section?.group?.collapsed ?? false;
   257→
   258→      setSectionCollapseStates((prev) => {
   259→        const currentCollapsed = prev.has(sectionIndex) ? prev.get(sectionIndex)! : configCollapsed;
   260→        const newCollapsed = !currentCollapsed;
   261→
   262→        // Store pending change to notify parent after render
   263→        pendingCollapseChangeRef.current = { sectionIndex, collapsed: newCollapsed };
   264→
   265→        const next = new Map(prev);
   266→        next.set(sectionIndex, newCollapsed);
   267→        return next;
   268→      });
   269→    }, []);
   270→
   271→    // Notify parent after state update settles
   272→    useEffect(() => {
   273→      if (pendingCollapseChangeRef.current) {
   274→        const { sectionIndex, collapsed } = pendingCollapseChangeRef.current;
   275→        pendingCollapseChangeRef.current = null;
   276→        onSectionCollapseChangeRef.current?.(sectionIndex, collapsed);
   277→      }
   278→    }, [sectionCollapseStates]);
   279→
   280→    const onPanelCollapsedChange = useCallback((globalPanelIndex: number, isCollapsed: boolean) => {
   281→      setPanelCollapseStates((prev) => {
   282→        const next = new Map(prev);
   283→        next.set(globalPanelIndex, isCollapsed);
   284→        return next;
   285→      });
   286→    }, []);
   287→
   288→    // Function to connect all chart instances together
   289→    const connectAllCharts = useCallback(() => {
   290→      const chartInstances: echarts.ECharts[] = subComponentRefs.current
   291→        .filter(
   292→          (chartRef): chartRef is DashboardVisualizationComponent =>
   293→            chartRef !== null &&
   294→            typeof (chartRef as unknown as { getEChartInstance?: () => echarts.ECharts })
   295→              .getEChartInstance === "function"
   296→        )
   297→        .map((chartRef) => {
   298→          const component = chartRef as unknown as { getEChartInstance: () => echarts.ECharts };
   299→          return component.getEChartInstance();
   300→        })
   301→        .filter((echartInstance) => echartInstance !== undefined);
   302→
   303→      if (chartInstances.length === 0) {
   304→        return;
   305→      }
   306→
   307→      const allCharts = getAllCharts(panels);
   308→      const chartNumber = allCharts.filter(
   309→        (chart: PanelDescriptor) => chart.type !== "table"
   310→      ).length;
   311→      if (chartInstances.length === chartNumber) {
   312→        // Connect all echarts together on this page
   313→        connect(chartInstances);
   314→      }
   315→    }, [panels]);
   316→
   317→    // Callback when a subcomponent is mounted or unmounted
   318→    const onSubComponentUpdated = useCallback(
   319→      (subComponent: DashboardVisualizationComponent | null, globalIndex: number) => {
   320→        subComponentRefs.current[globalIndex] = subComponent;
   321→        connectAllCharts();
   322→      },
   323→      [connectAllCharts]
   324→    );
   325→
   326→    const refreshAllCharts = useCallback(
   327→      (newTimeSpan?: TimeSpan, newFilterExpression?: string) => {
   328→        const refreshParam: RefreshOptions = {
   329→          timeSpan: newTimeSpan ?? initialTimeSpan,
   330→          filterExpression: newFilterExpression ?? initialFilterExpression,
   331→          forceRefresh: true,
   332→        };
   333→
   334→        subComponentRefs.current.forEach((chart) => {
   335→          if (chart !== null) {
   336→            chart.refresh(refreshParam);
   337→          }
   338→        });
   339→
   340→        // Also refresh all registered child components
   341→        registeredChildrenRef.current.forEach((child) => {
   342→          child.refresh(
   343→            newTimeSpan ?? initialTimeSpan,
   344→            newFilterExpression ?? initialFilterExpression
   345→          );
   346→        });
   347→      },
   348→      [initialTimeSpan, initialFilterExpression]
   349→    );
   350→
   351→    // Expose refresh method via imperative handle
   352→    useImperativeHandle(
   353→      ref,
   354→      () => ({
   355→        refresh: (timeSpan?: TimeSpan, filterExpression?: string) => {
   356→          refreshAllCharts(timeSpan, filterExpression);
   357→        },
   358→      }),
   359→      [refreshAllCharts]
   360→    );
   361→
   362→    // Context value for child registration
   363→    const contextValue = useMemo<DashboardRefreshContextValue>(
   364→      () => ({
   365→        register: (child: RefreshableChild) => {
   366→          registeredChildrenRef.current.add(child);
   367→        },
   368→        unregister: (child: RefreshableChild) => {
   369→          registeredChildrenRef.current.delete(child);
   370→        },
   371→      }),
   372→      []
   373→    );
   374→
   375→    // Generate a stable dashboard ID for layout persistence
   376→    const effectiveDashboardId = dashboardId ?? dashboard.name ?? "default";
   377→
   378→    return (
   379→      <DashboardRefreshContext.Provider value={contextValue}>
   380→        <div className="h-full flex flex-col overflow-hidden">
   381→          <div className="flex-1 overflow-y-auto overflow-x-hidden">
   382→            {sections.map((section) => {
   383→              // Use local state for collapse only (no persistence)
   384→              const isCollapsed = sectionCollapseStates.get(section.sectionIndex) ?? false;
   385→
   386→              return (
   387→                <DashboardSection
   388→                  key={`section-${section.sectionIndex}`}
   389→                  dashboardId={effectiveDashboardId}
   390→                  sectionIndex={section.sectionIndex}
   391→                  group={section.group}
   392→                  panels={section.panels}
   393→                  isCollapsed={isCollapsed}
   394→                  onToggleCollapse={() => handleSectionToggle(section.sectionIndex)}
   395→                  onSubComponentUpdated={onSubComponentUpdated}
   396→                  globalPanelStartIndex={section.globalPanelStartIndex}
   397→                  initialTimeSpan={initialTimeSpan}
   398→                  initialFilterExpression={initialFilterExpression}
   399→                  initialLoading={initialLoading}
   400→                  panelCollapseStates={panelCollapseStates}
   401→                  onPanelCollapsedChange={onPanelCollapsedChange}
   402→                  onChartSelection={onChartSelection}
   403→                  showEditControls={showSectionEditControls && section.group !== null}
   404→                  onRename={onSectionRename ? (title) => onSectionRename(section.sectionIndex, title) : undefined}
   405→                  onDelete={onSectionDelete ? () => onSectionDelete(section.sectionIndex) : undefined}
   406→                />
   407→              );
   408→            })}
   409→            {children}
   410→          </div>
   411→        </div>
   412→      </DashboardRefreshContext.Provider>
   413→    );
   414→  }
   415→);
   416→
   417→export default DashboardPanelContainer;
   418→

