     8→
     9→export interface SectionHeaderProps {
    10→  /** Section title */
    11→  title: string;
    12→  /** Whether the section is collapsed */
    13→  isCollapsed: boolean;
    14→  /** Callback when collapse state changes */
    15→  onToggleCollapse: () => void;
    16→  /** Whether edit controls should be shown (for custom dashboards) */
    17→  showEditControls?: boolean;
    18→  /** Callback when section is renamed */
    19→  onRename?: (newTitle: string) => void;
    20→  /** Callback when section is deleted */
    21→  onDelete?: () => void;
    22→  /** Additional CSS classes */
    23→  className?: string;
    24→}
    25→
    26→/**
    27→ * Section header component with collapse toggle and optional edit controls.
    28→ * Used to group dashboard panels into collapsible sections.
    29→ */
    30→export function SectionHeader({
    31→  title,
    32→  isCollapsed,
    33→  onToggleCollapse,
    34→  showEditControls = false,
    35→  onRename,
    36→  onDelete,
    37→  className,
    38→}: SectionHeaderProps) {
    39→  const [isEditing, setIsEditing] = useState(false);
    40→  const [editValue, setEditValue] = useState(title);
    41→  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    42→  const inputRef = useRef<HTMLInputElement>(null);
    43→
    44→  // Focus input when entering edit mode
    45→  useEffect(() => {
    46→    if (isEditing && inputRef.current) {
    47→      inputRef.current.focus();
    48→      inputRef.current.select();
    49→    }
    50→  }, [isEditing]);
    51→
    52→  // Reset edit value when title changes externally
    53→  useEffect(() => {
    54→    setEditValue(title);
    55→  }, [title]);
    56→
    57→  const handleSaveRename = useCallback(() => {
    58→    const trimmed = editValue.trim();
    59→    if (trimmed && trimmed !== title && onRename) {
    60→      onRename(trimmed);
    61→    }
    62→    setIsEditing(false);
    63→  }, [editValue, title, onRename]);
    64→
    65→  const handleCancelRename = useCallback(() => {
    66→    setEditValue(title);
    67→    setIsEditing(false);
    68→  }, [title]);
    69→
    70→  const handleKeyDown = useCallback(
    71→    (e: React.KeyboardEvent) => {
    72→      if (e.key === "Enter") {
    73→        handleSaveRename();
    74→      } else if (e.key === "Escape") {
    75→        handleCancelRename();
    76→      }
    77→    },
    78→    [handleSaveRename, handleCancelRename]
    79→  );
    80→
    81→  const handleDelete = useCallback(() => {
    82→    if (showDeleteConfirm && onDelete) {
    83→      onDelete();
    84→      setShowDeleteConfirm(false);
    85→    } else {
    86→      setShowDeleteConfirm(true);
    87→    }
    88→  }, [showDeleteConfirm, onDelete]);
    89→
    90→  const handleCancelDelete = useCallback(() => {
    91→    setShowDeleteConfirm(false);
    92→  }, []);
    93→
    94→  return (
    95→    <div
    96→      className={cn(
    97→        "flex items-center gap-2 px-2 py-1.5 bg-muted/30 border-b select-none group",
    98→        className
    99→      )}
   100→    >
   101→      {/* Collapse toggle */}
   102→      <button
   103→        type="button"
   104→        onClick={onToggleCollapse}
   105→        className="flex items-center gap-1.5 flex-1 min-w-0 text-left hover:bg-muted/50 rounded px-1 py-0.5 transition-colors"
   106→        aria-expanded={!isCollapsed}
   107→        aria-label={isCollapsed ? `Expand ${title}` : `Collapse ${title}`}
   108→      >
   109→        <ChevronRight
   110→          className={cn(
   111→            "h-4 w-4 shrink-0 text-muted-foreground transition-transform duration-200",
   112→            !isCollapsed && "rotate-90"
   113→          )}
   114→        />
   115→        {isEditing ? (
   116→          <Input
   117→            ref={inputRef}
   118→            value={editValue}
   119→            onChange={(e) => setEditValue(e.target.value)}
   120→            onKeyDown={handleKeyDown}
   121→            onBlur={handleSaveRename}
   122→            className="h-6 text-sm font-medium px-1 py-0"
   123→            onClick={(e) => e.stopPropagation()}
   124→          />
   125→        ) : (
   126→          <span className="text-sm font-medium truncate">{title}</span>
   127→        )}
   128→      </button>
   129→
   130→      {/* Edit controls (visible on hover for custom dashboards) */}
   131→      {showEditControls && !isEditing && (
   132→        <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
   133→          {showDeleteConfirm ? (
   134→            <>
   135→              <span className="text-xs text-muted-foreground mr-1">Delete?</span>
   136→              <Button
   137→                variant="ghost"
   138→                size="icon"
   139→                className="h-6 w-6 text-destructive hover:text-destructive"
   140→                onClick={handleDelete}
   141→                title="Confirm delete"
   142→              >
   143→                <Check className="h-3.5 w-3.5" />
   144→              </Button>
   145→              <Button
   146→                variant="ghost"
   147→                size="icon"
   148→                className="h-6 w-6"
   149→                onClick={handleCancelDelete}
   150→                title="Cancel"
   151→              >
   152→                <X className="h-3.5 w-3.5" />
   153→              </Button>
   154→            </>
   155→          ) : (
   156→            <>
   157→              <Button
   158→                variant="ghost"
   159→                size="icon"
   160→                className="h-6 w-6"
   161→                onClick={(e) => {
   162→                  e.stopPropagation();
   163→                  setIsEditing(true);
   164→                }}
   165→                title="Rename section"
   166→              >
   167→                <Pencil className="h-3.5 w-3.5" />
   168→              </Button>
   169→              <Button
   170→                variant="ghost"
   171→                size="icon"
   172→                className="h-6 w-6 text-muted-foreground hover:text-destructive"
   173→                onClick={(e) => {
   174→                  e.stopPropagation();
   175→                  handleDelete();
   176→                }}
   177→                title="Delete section"
   178→              >
   179→                <Trash2 className="h-3.5 w-3.5" />
   180→              </Button>
   181→            </>
   182→          )}
   183→        </div>
   184→      )}
   185→
   186→      {/* Save/Cancel buttons when editing */}
   187→      {isEditing && (
   188→        <div className="flex items-center gap-0.5">
   189→          <Button
   190→            variant="ghost"
   191→            size="icon"
   192→            className="h-6 w-6"
   193→            onClick={handleSaveRename}
   194→            title="Save"
   195→          >
   196→            <Check className="h-3.5 w-3.5" />
   197→          </Button>
   198→          <Button
   199→            variant="ghost"
   200→            size="icon"
   201→            className="h-6 w-6"
   202→            onClick={handleCancelRename}
   203→            title="Cancel"
   204→          >
   205→            <X className="h-3.5 w-3.5" />
   206→          </Button>
   207→        </div>
   208→      )}
   209→    </div>
   210→  );
   211→}
