    sm.push({
      i: key,
      x: 0,
      y: index * 4,
      w: 1,
      h: gridPos.h,
      minW: 1,
      minH: constraints.minH,
      maxW: 1,
      maxH: constraints.maxH,
      static: true,
    });
  });

